// 1. Iterate over each incoming item
const results = items.map(item => {
  // Get the raw string from the 'text' field
  let rawContent = item.json.text;

  // 2. CLEANUP: Remove Markdown code blocks (```json ... ```)
  // This regex removes the start ```json (case insensitive) and the end ```
  rawContent = rawContent.replace(/^```json\s*/i, "")
                         .replace(/^```\s*/, "")
                         .replace(/\s*```$/, "");

  // 3. PARSE: Convert the clean string into a real JavaScript object
  try {
    const data = JSON.parse(rawContent);

    // Return the specific fields you requested
    return {mentions:{
      visibility_score: data.visibility_score,
      brand_position: data.brand_position,
      brand_analyzed: data.brand_analyzed,
      total_brands: data.total_brands,
      brand_mentions: data.brand_mentions
    }}
  } catch (error) {
    // Returns an error object if one of the inputs is bad JSON
    return { error: "Failed to parse JSON", raw_input: rawContent };
  }
});

// 4. OUTPUT: Return the single object with the 'mentions' array
return results;

// 1. Get all input items
const items = $input.all();

// Get current date and format as YYYY-MM-DD
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const currentDate = `${year}-${month}-${day}`;

// 2. Identify ALL unique column names from ALL items
const keySet = new Set();
items.forEach(item => {
  if (item.json) {
    Object.keys(item.json).forEach(key => keySet.add(key));
  }
});
const keys = Array.from(keySet);

// 3. Create temporary storage for cleaned columns
const columns = {};
keys.forEach(key => columns[key] = []);

// 4. Iterate through every row and extract valid data
items.forEach(item => {
  keys.forEach(key => {
    const value = item.json[key];
    if (value !== undefined && value !== null && value !== "") {
      columns[key].push(value);
    }
  });
});

// 5. Determine the max height of the new table
let maxRows = 0;
keys.forEach(key => {
  if (columns[key].length > maxRows) {
    maxRows = columns[key].length;
  }
});

// 6. Reconstruct the rows
const result = [];

for (let i = 0; i < maxRows; i++) {
  const newRow = {};

  // Apply the dynamic date
  newRow["date"] = currentDate;

  keys.forEach(key => {
    newRow[key] = columns[key][i] !== undefined ? columns[key][i] : null;
  });

  result.push({ json: newRow });
}

return result;

