const items = $input.all();

return items.map(item => {
    const data = item.json;

    // The new model puts the array inside 'output'
    const outputArray = data.output || [];

    let extractedText = null;
    let extractedAnnotations = [];
    let extractedSources = [];
    let extractedQueries = [];

    // Loop through every item in the output array, regardless of its position
    for (const event of outputArray) {

        // 1. If this event is a search call, grab the sources and queries
        if (event.type === "web_search_call" && event.action) {
            if (event.action.sources) {
                // Add these sources to our master list
                extractedSources = extractedSources.concat(event.action.sources);
            }
            if (event.action.queries) {
                // Add these queries to our master list
                extractedQueries = extractedQueries.concat(event.action.queries);
            }
        }

        // 2. If this event is the final message, grab the text and annotations
        if (event.type === "message" && event.content && event.content[0]) {
            const contentBlock = event.content[0];
            if (contentBlock.type === "output_text") {
                extractedText = contentBlock.text || null;
                extractedAnnotations = (contentBlock.annotations || []).map(annotation => ({
            title: annotation.title,
            url: annotation.url
        }));
            }
        }
    }

    // 3. Deduplicate sources (since multiple searches might return the same URL)
    const uniqueSources = [];
    const seenUrls = new Set();
    for (const source of extractedSources) {
        if (source.url && !seenUrls.has(source.url)) {
            seenUrls.add(source.url);
            uniqueSources.push(source.url);
        }
    }

    // 4. Return the exact structure your downstream nodes expect
    return {
        json: {
            textContent: extractedText,
            annotations: extractedAnnotations,
            sources: uniqueSources,
            // Use Set to remove duplicate queries
            queries: [...new Set(extractedQueries)]
        }
    };
});

// Fan out: queries × platforms, carrying Brand and SheetID on every item
const platforms = ['gpt', 'perplexity', 'ai_mode'];

const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  // Handle the input shape:
  // { body: { Brand, Query: [...] }, SheetID }
  const brand = data.body?.Brand ?? data.Brand;
  const queries = data.body?.Query ?? data.Query ?? [];
  const sheetId = data.SheetID ?? data.sheetId;

  // Normalize: Query may be a single string or an array
  const queryList = Array.isArray(queries) ? queries : [queries];

  for (const query of queryList) {
    for (const platform of platforms) {
      output.push({
        json: {
          Brand: brand,
          SheetID: sheetId,
          query: query,
          platform: platform,
        },
      });
    }
  }
}

return output;
